 function dedupeCandidates(candidates) {
   const seen = new Set();
   return candidates.filter((candidate) => {
     const key = `${candidate.id}:${candidate.reasoningEffort || ""}`;
     if (seen.has(key)) {
       return false;
     }
     seen.add(key);
     return true;
